class TreeNode {
    private String name;
    private int memberCount;
    private int depth;
    private List<TreeNode> children = new ArrayList<>();

    public TreeNode(String name, int memberCount, int depth) {
        this.name = name;
        this.memberCount = memberCount;
        this.depth = depth;
    }

    public void addChild(TreeNode child) { children.add(child); }
    public int getDepth() { return depth; }
    public List<TreeNode> getChildren() { return children; }
}

public class TeamTreeBuilder {
    public TreeNode buildTeamTree(String filePath) throws IOException {
        ObjectMapper mapper = new ObjectMapper();
        List<TeamData> teams = mapper.readValue(new File(filePath), new TypeReference<List<TeamData>>() {});

        TreeNode root = new TreeNode("Organization", 0, 0);
        Queue<TreeNode> queue = new LinkedList<>();
        queue.add(root);

        for (TeamData team : teams) {
            if (queue.isEmpty()) break;
            TreeNode parent = queue.poll();
            int childDepth = parent.getDepth() + 1;
            TreeNode child = new TreeNode(team.getTeamName(), team.getMembers().size(), childDepth);
            parent.addChild(child);
            if (parent.getChildren().size() < 3) queue.offer(parent);
            if (childDepth < 3) queue.offer(child);
        }

        return root;
    }
}
