#include <vector>
#include <string>
#include <unordered_map>
#include <queue>
using namespace std;

struct Employee {
    string name;
    vector<int> salaries;
};

struct TreeNode {
    int value;
    string name;
    vector<TreeNode*> children;
    int depth;
    TreeNode(int v, string n, int d) : value(v), name(n), depth(d) {}
};

TreeNode* constructTree(vector<Employee> employees, vector<pair<string, string>> hierarchy) {
    unordered_map<string, Employee> empMap;
    for (const auto& emp : employees) {
        empMap[emp.name] = emp;
    }

    unordered_map<string, vector<string>> adjList;
    unordered_map<string, bool> isEmployee;
    for (const auto& pair : hierarchy) {
        adjList[pair.first].push_back(pair.second);
        isEmployee[pair.second] = true;
    }

    string rootName;
    for (const auto& emp : employees) {
        if (!isEmployee.count(emp.name)) {
            rootName = emp.name;
            break;
        }
    }

    int rootMax = 0;
    for (int salary : empMap[rootName].salaries) {
        if (salary > rootMax) rootMax = salary;
    }

    TreeNode* root = new TreeNode(rootMax, rootName, 0);
    unordered_map<string, TreeNode*> nodeMap;
    nodeMap[rootName] = root;

    queue<TreeNode*> q;
    q.push(root);

    while (!q.empty()) {
        TreeNode* current = q.front();
        q.pop();

        if (current->depth >= 3 || current->children.size() >= 2) continue;

        if (adjList.find(current->name) == adjList.end()) continue;

        for (const string& subName : adjList[current->name]) {
            if (nodeMap.count(subName) || current->children.size() >= 2) break;
            if (empMap.find(subName) == empMap.end()) continue;

            const Employee& emp = empMap[subName];
            int maxSal = 0;
            for (int s : emp.salaries) if (s > maxSal) maxSal = s;

            TreeNode* child = new TreeNode(maxSal, subName, current->depth + 1);
            current->children.push_back(child);
            nodeMap[subName] = child;

            if (child->depth < 3) q.push(child);
        }
    }

    return root;
}
