#[derive(Debug)]
struct Node {
    id: i32,
    children: Vec<Box<Node>>,
}

fn build_tree(tuples: Vec<(i32, i32)>) -> Node {
    let mut parent_map: HashMap<i32, Vec<i32>> = HashMap::new();
    for (node_id, parent_id) in tuples {
        parent_map.entry(parent_id).or_insert_with(Vec::new).push(node_id);
    }
    build_node(0, 1, &parent_map)
}

fn build_node(id: i32, depth: u32, parent_map: &HashMap<i32, Vec<i32>>) -> Node {
    let mut children = Vec::new();
    if depth < 3 {
        if let Some(child_ids) = parent_map.get(&id) {
            for child_id in child_ids.iter().take(2) {
                children.push(Box::new(build_node(*child_id, depth + 1, parent_map)));
            }
        }
    }
    Node { id, children }
}
