    let current_time = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs() as i64;
    let one_hour_ago = current_time.saturating_sub(3600);
    let mut candidates: HashSet<i64> = timestamps
        .into_iter()
        .filter(|&t| t >= one_hour_ago && t <= current_time)
        .collect();
