def validate_email(email):
    if len(email) > 254:
        return False
    if email.count('@') != 1:
        return False
    local, domain = email.split('@')
    if not local or not domain:
        return False
    if '.' not in domain:
        return False
    if domain.startswith('.') or domain.endswith('.'):
        return False
    tld = domain.split('.')[-1]
    if len(tld) < 2:
        return False
    return True
